CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`talent`.`participation_statement` (
    `participation_statement_id` BIGINT COMMENT 'Primary key for participation statement',
    `contract_id` BIGINT COMMENT 'FK to talent contract',
    `participation_definition_id` BIGINT COMMENT 'FK to participation definition',
    `talent_profile_id` BIGINT COMMENT 'FK to talent profile',
    `title_id` BIGINT COMMENT 'FK to content title',
    `adjusted_gross_amount` DECIMAL(18,2) COMMENT 'Adjusted gross receipts amount',
    `amount_paid` DECIMAL(18,2) COMMENT 'Amount already paid',
    `audited_flag` BOOLEAN COMMENT 'Whether statement has been audited',
    `balance_amount` DECIMAL(18,2) COMMENT 'Outstanding balance',
    `breakeven_reached_flag` BOOLEAN COMMENT 'Whether breakeven has been reached',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `cumulative_net_amount` DECIMAL(18,2) COMMENT 'Cumulative net amount to date',
    `currency_code` STRING COMMENT 'ISO currency code',
    `deductible_costs_amount` DECIMAL(18,2) COMMENT 'Deductible costs applied',
    `distribution_fee_amount` DECIMAL(18,2) COMMENT 'Distribution fees deducted',
    `gross_receipts_amount` DECIMAL(18,2) COMMENT 'Total gross receipts for the period',
    `issued_date` DATE COMMENT 'Date statement was issued to talent',
    `net_proceeds_amount` DECIMAL(18,2) COMMENT 'Net proceeds after all deductions',
    `net_profit_amount` DECIMAL(18,2) COMMENT 'Net profit after deductions',
    `participation_amount_due` DECIMAL(18,2) COMMENT 'Participation amount due this period',
    `source_system_code` STRING COMMENT 'ID in the source system',
    `statement_date` DATE COMMENT 'Date the statement was generated',
    `statement_number` STRING COMMENT 'Unique statement reference number',
    `statement_period_end` DATE COMMENT 'End of the statement period',
    `statement_period_start` DATE COMMENT 'Start of the statement period',
    `statement_status` STRING COMMENT 'Lifecycle status of the statement',
    `participation_statement_status` STRING COMMENT 'Statement status',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    CONSTRAINT pk_participation_statement PRIMARY KEY(`participation_statement_id`)
) COMMENT 'Periodic statement of participation earnings computed against defined participation terms';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`talent`.`bonus_trigger` (
    `bonus_trigger_id` BIGINT COMMENT 'Primary key for bonus trigger',
    `compensation_structure_id` BIGINT COMMENT 'FK to compensation structure',
    `contract_id` BIGINT COMMENT 'FK to talent contract',
    `talent_profile_id` BIGINT COMMENT 'FK to talent profile',
    `title_id` BIGINT COMMENT 'FK to content title',
    `bonus_amount` DECIMAL(18,2) COMMENT 'Fixed bonus amount if triggered',
    `bonus_percentage` DECIMAL(18,2) COMMENT 'Percentage bonus if triggered',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `currency_code` STRING COMMENT 'ISO currency code',
    `is_triggered` BOOLEAN COMMENT 'Whether the trigger has been activated',
    `is_triggered_flag` BOOLEAN COMMENT 'Boolean flag indicating trigger activation',
    `measurement_window_end` DATE COMMENT 'End of measurement window',
    `measurement_window_start` DATE COMMENT 'Start of measurement window',
    `paid_date` DATE COMMENT 'Date the bonus was paid',
    `paid_flag` BOOLEAN COMMENT 'Whether the bonus has been paid',
    `payment_status` STRING COMMENT 'Payment processing status',
    `source_system_code` STRING COMMENT 'ID in the source system',
    `bonus_trigger_status` STRING COMMENT 'Current status of the bonus trigger',
    `threshold_metric` STRING COMMENT 'Metric name for threshold evaluation',
    `threshold_unit` STRING COMMENT 'Unit of measurement for threshold',
    `threshold_value` DECIMAL(18,2) COMMENT 'Threshold value that triggers the bonus',
    `trigger_metric` STRING COMMENT 'Specific metric being measured',
    `trigger_type` STRING COMMENT 'Type of trigger (box_office, viewership, award, streaming)',
    `triggered_date` DATE COMMENT 'Date the trigger was activated',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    CONSTRAINT pk_bonus_trigger PRIMARY KEY(`bonus_trigger_id`)
) COMMENT 'Contingent compensation triggers based on box-office, viewership, awards, or other performance metrics';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`talent`.`participation_definition` (
    `participation_definition_id` BIGINT COMMENT 'Primary key for participation definition',
    `contract_id` BIGINT COMMENT 'FK to the talent contract',
    `talent_profile_id` BIGINT COMMENT 'FK to the talent profile',
    `title_id` BIGINT COMMENT 'FK to the content title',
    `_created_at` TIMESTAMP COMMENT 'Lineage creation timestamp',
    `_updated_at` TIMESTAMP COMMENT 'Lineage update timestamp',
    `breakeven_amount` DECIMAL(18,2) COMMENT 'Breakeven amount threshold',
    `breakeven_basis` STRING COMMENT 'Basis for breakeven calculation',
    `breakeven_definition` STRING COMMENT 'Detailed breakeven definition text',
    `cap_amount` DECIMAL(18,2) COMMENT 'Maximum cap on participation payout',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `deductions_definition` STRING COMMENT 'Definition of allowable deductions',
    `deductions_description` STRING COMMENT 'Narrative description of deductions',
    `definition_basis` STRING COMMENT 'Basis for participation calculation',
    `definition_name` STRING COMMENT 'Human-readable name for this definition',
    `definition_status` STRING COMMENT 'Lifecycle status of the definition',
    `distribution_fee_percentage` DECIMAL(18,2) COMMENT 'Distribution fee percentage applied',
    `effective_date` DATE COMMENT 'Date participation terms become effective',
    `expiration_date` DATE COMMENT 'Date participation terms expire',
    `first_dollar_flag` BOOLEAN COMMENT 'First dollar participation flag',
    `first_dollar_gross_flag` BOOLEAN COMMENT 'Whether participation is from first dollar gross',
    `floor_amount` DECIMAL(18,2) COMMENT 'Minimum floor guarantee amount',
    `interest_basis` STRING COMMENT 'Basis for interest calculation on unrecouped',
    `overhead_percentage` DECIMAL(18,2) COMMENT 'Overhead percentage applied',
    `participation_percentage` DECIMAL(18,2) COMMENT 'Percentage of participation',
    `participation_type` STRING COMMENT 'Type of participation (gross, adjusted_gross, net)',
    `rolling_breakeven_flag` BOOLEAN COMMENT 'Whether breakeven rolls forward',
    `source_system_code` STRING COMMENT 'ID in the source system',
    `participation_definition_status` STRING COMMENT 'Current status of the participation definition',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    CONSTRAINT pk_participation_definition PRIMARY KEY(`participation_definition_id`)
) COMMENT 'Defines gross/adjusted-gross/net participation terms for high-end talent deals';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`talent`.`deferred_compensation` (
    `deferred_compensation_id` BIGINT COMMENT 'Primary key for deferred compensation',
    `compensation_structure_id` BIGINT COMMENT 'FK to compensation structure',
    `contract_id` BIGINT COMMENT 'FK to talent contract',
    `talent_profile_id` BIGINT COMMENT 'FK to talent profile',
    `title_id` BIGINT COMMENT 'FK to content title',
    `amount_paid` DECIMAL(18,2) COMMENT 'Total amount paid to date',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `currency_code` STRING COMMENT 'ISO currency code',
    `deferral_trigger` STRING COMMENT 'Event that triggers deferral payout',
    `deferral_type` STRING COMMENT 'Type of deferral arrangement',
    `deferred_amount` DECIMAL(18,2) COMMENT 'Total deferred amount',
    `interest_rate` DECIMAL(18,2) COMMENT 'Interest rate applied to deferred amount',
    `is_fully_paid` BOOLEAN COMMENT 'Whether the deferred comp is fully paid',
    `is_payable_flag` BOOLEAN COMMENT 'Whether the deferred comp is currently payable',
    `outstanding_amount` DECIMAL(18,2) COMMENT 'Remaining outstanding amount',
    `paid_amount` DECIMAL(18,2) COMMENT 'Amount paid out so far',
    `payout_date` DATE COMMENT 'Scheduled or actual payout date',
    `scheduled_payment_date` DATE COMMENT 'Next scheduled payment date',
    `source_system_code` STRING COMMENT 'ID in the source system',
    `deferred_compensation_status` STRING COMMENT 'Current status of the arrangement',
    `trigger_condition` STRING COMMENT 'Condition that triggers payout eligibility',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    `vested_amount` DECIMAL(18,2) COMMENT 'Amount currently vested',
    `vesting_end_date` DATE COMMENT 'End date of vesting schedule',
    `vesting_schedule` STRING COMMENT 'Description of vesting schedule (cliff, graded, etc.)',
    `vesting_start_date` DATE COMMENT 'Start date of vesting schedule',
    CONSTRAINT pk_deferred_compensation PRIMARY KEY(`deferred_compensation_id`)
) COMMENT 'Deferred compensation arrangements for talent including vesting schedules and payout triggers';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`talent`.`talent_sports_team` (
    `talent_sports_team_id` BIGINT COMMENT 'Surrogate primary key for the sports team.',
    `active_flag` BOOLEAN COMMENT 'Whether the team is currently active.',
    `city` STRING COMMENT 'Home city / market of the team.',
    `conference_division` STRING COMMENT 'Conference or division grouping.',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp.',
    `founded_year` STRING COMMENT 'Year the team was founded.',
    `jersey_number` STRING COMMENT 'Uniform/jersey number assigned.',
    `league_name` STRING COMMENT 'League the team competes in (NFL/NBA/UEFA).',
    `performance_rights_flag` BOOLEAN COMMENT 'Whether performance rights are held for this team.',
    `roster` STRING COMMENT 'Roster designation or membership.',
    `source_system_code` STRING COMMENT 'Identifier in the source system.',
    `team_abbreviation` STRING COMMENT 'Short code (e.g. NYG, LAL).',
    `team_name` STRING COMMENT 'Full club / team name.',
    `updated_at` TIMESTAMP COMMENT 'Record last-updated timestamp.',
    `venue_name` STRING COMMENT 'Primary home venue / stadium name.',
    CONSTRAINT pk_talent_sports_team PRIMARY KEY(`talent_sports_team_id`)
) COMMENT 'Sports team / club competing in a league or competition (roster owner).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`talent`.`talent_athlete` (
    `talent_athlete_id` BIGINT COMMENT 'Surrogate primary key for the athlete.',
    `content_sports_team_id` BIGINT COMMENT '',
    `talent_sports_team_id` BIGINT COMMENT 'FK to the athletes sports team.',
    `talent_profile_id` BIGINT COMMENT 'FK to the associated talent profile if applicable.',
    `active_flag` BOOLEAN COMMENT 'Whether the athlete is currently active.',
    `athlete_name` STRING COMMENT '',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp.',
    `date_of_birth` DATE COMMENT 'Athlete date of birth.',
    `full_name` STRING COMMENT 'Athlete full name.',
    `height_cm` DECIMAL(18,2) COMMENT 'Height in centimetres.',
    `jersey_number` STRING COMMENT 'Roster jersey number.',
    `nationality` STRING COMMENT 'Athlete nationality.',
    `performance_rights_flag` BOOLEAN COMMENT 'Whether performance rights are held for this athlete.',
    `position` STRING COMMENT 'Playing position / role.',
    `roster` STRING COMMENT 'Roster designation or membership.',
    `roster_status` STRING COMMENT 'Roster status (active/injured/inactive).',
    `source_system_code` STRING COMMENT 'Identifier in the source system.',
    `updated_at` TIMESTAMP COMMENT 'Record last-updated timestamp.',
    `weight_kg` DECIMAL(18,2) COMMENT 'Weight in kilograms.',
    CONSTRAINT pk_talent_athlete PRIMARY KEY(`talent_athlete_id`)
) COMMENT 'Individual athlete / player on a sports team roster.';

